import { useEffect, useRef, useState } from 'react';
import { useScrollReveal } from '../hooks/useScrollReveal';
import './Skills.css';

const SKILLS = [
  {
    category: 'Frontend',
    emoji: '🖥️',
    color: '#06B6D4',
    desc: 'Building fast, accessible, pixel-perfect interfaces.',
    items: ['React', 'TypeScript', 'Next.js', 'HTML/CSS', 'TailwindCSS'],
  },
  {
    category: 'Backend',
    emoji: '⚙️',
    color: '#7C3AED',
    desc: 'Scalable APIs, databases, and server-side logic.',
    items: ['Node.js', 'Python', 'FastAPI', 'PostgreSQL', 'Redis'],
  },
  {
    category: 'Fintech',
    emoji: '💳',
    color: '#10B981',
    desc: 'Payment flows, KYC, escrow, and fraud signals.',
    items: ['Paystack', 'Flutterwave', 'KYC Flows', 'Escrow Architecture', 'Fraud Signals'],
  },
  {
    category: 'Video',
    emoji: '🎬',
    color: '#F59E0B',
    desc: 'Commercial edits, colour grading, motion graphics.',
    items: ['Premiere Pro', 'After Effects', 'DaVinci Resolve', 'Colour Grading', 'Motion Graphics'],
  },
  {
    category: 'Tools',
    emoji: '🛠️',
    color: '#EC4899',
    desc: 'The glue that holds every project together.',
    items: ['Git', 'Docker', 'Figma', 'Supabase', 'Firebase'],
  },
];

const RADIUS  = 200;
const AUTO_MS = 3000;

export default function Skills() {
  const titleRef            = useScrollReveal();
  const sectionRef          = useScrollReveal();
  const [active, setActive] = useState(0);
  const [angle, setAngle]   = useState(0);
  const timerRef            = useRef(null);
  const dragging            = useRef(false);
  const dragStart           = useRef(0);
  const angleAtDrag         = useRef(0);

  const count   = SKILLS.length;
  const stepDeg = 360 / count;

  const startAuto = () => {
    clearInterval(timerRef.current);
    timerRef.current = setInterval(() => {
      setAngle(a => a - stepDeg);
    }, AUTO_MS);
  };

  useEffect(() => {
    startAuto();
    return () => clearInterval(timerRef.current);
  }, []);

  useEffect(() => {
    const normalized = (((-angle % 360) + 360) % 360);
    const idx = Math.round(normalized / stepDeg) % count;
    setActive(idx);
  }, [angle]);

  const onPointerDown = (e) => {
    dragging.current    = true;
    dragStart.current   = e.clientX;
    angleAtDrag.current = angle;
    clearInterval(timerRef.current);
    e.currentTarget.setPointerCapture(e.pointerId);
  };
  const onPointerMove = (e) => {
    if (!dragging.current) return;
    setAngle(angleAtDrag.current + (e.clientX - dragStart.current) * 0.4);
  };
  const onPointerUp = () => {
    dragging.current = false;
    startAuto();
  };

  const focusNode = (i) => {
    clearInterval(timerRef.current);
    setAngle(-i * stepDeg);
    setActive(i);
    setTimeout(startAuto, AUTO_MS * 2);
  };

  const skill = SKILLS[active];

  return (
    <section className="skills section" id="skills">
      <div className="section__inner">
        <div className="section__label">Toolkit</div>
        <h2 className="section__heading reveal" ref={titleRef}>
          Skills &amp; <span className="gradient-text">technologies</span>
        </h2>

        <div className="skills__stage reveal" ref={sectionRef}>
          <div
            className="skills__orbit-wrap"
            onPointerDown={onPointerDown}
            onPointerMove={onPointerMove}
            onPointerUp={onPointerUp}
            onPointerLeave={onPointerUp}
          >
            <div className="skills__ring skills__ring--1" aria-hidden />
            <div className="skills__ring skills__ring--2" aria-hidden />

            <div
              className="skills__orbit"
              style={{ transform: `rotateY(${angle}deg)` }}
            >
              {SKILLS.map((s, i) => (
                <button
                  key={s.category}
                  className={`skills__node${i === active ? ' skills__node--active' : ''}`}
                  style={{
                    '--node-color': s.color,
                    transform: `rotateY(${i * stepDeg}deg) translateZ(${RADIUS}px)`,
                  }}
                  onClick={() => focusNode(i)}
                  aria-label={s.category}
                >
                  <span className="skills__node-emoji">{s.emoji}</span>
                  <span className="skills__node-label">{s.category}</span>
                </button>
              ))}
            </div>

            <div className="skills__centre" style={{ '--node-color': skill.color }}>
              <span className="skills__centre-emoji">{skill.emoji}</span>
            </div>
          </div>

          <div className="skills__panel" key={active}>
            <p className="skills__panel-cat" style={{ color: skill.color }}>
              {skill.category}
            </p>
            <p className="skills__panel-desc">{skill.desc}</p>
            <div className="skills__chips">
              {skill.items.map((item, i) => (
                <span
                  key={item}
                  className="skills__chip"
                  style={{ animationDelay: `${i * 0.06}s`, '--chip-color': skill.color }}
                >
                  {item}
                </span>
              ))}
            </div>
          </div>
        </div>

        <div className="skills__dots" role="tablist">
          {SKILLS.map((s, i) => (
            <button
              key={s.category}
              className={`skills__dot${i === active ? ' skills__dot--active' : ''}`}
              style={{ '--dot-color': s.color }}
              onClick={() => focusNode(i)}
              role="tab"
              aria-selected={i === active}
              aria-label={s.category}
            />
          ))}
        </div>
      </div>
    </section>
  );
}
